  const existingIds = lastRow > 1 ? 
    sheet.getRange(2, 1, lastRow - 1, 1).getValues().flat() : [];

  // Find highest existing ID number
  let maxId = 0;
  existingIds.forEach(id => {
    if (id && String(id).startsWith(config.prefix)) {
